create extension if not exists "pgcrypto";
create table if not exists users (id uuid primary key references auth.users(id) on delete cascade,name text not null,email text unique not null,phone text,role text check (role in ('customer','provider','admin')) not null,location text,avatar_url text,created_at timestamptz default now());
create table if not exists provider_profiles (id uuid primary key default gen_random_uuid(),user_id uuid unique references users(id) on delete cascade,phone text,address text,skills text[] default '{}',bio text,experience_years integer default 0,insurance_number text,right_to_work_confirmed boolean default false,dbs_confirmed boolean default false,id_document_url text,proof_of_address_url text,stripe_account_id text,stripe_onboarding_complete boolean default false,provider_mode text check (provider_mode in ('online','busy','offline')) default 'offline',travel_radius_miles integer default 10,base_latitude numeric,base_longitude numeric,verification_status text check (verification_status in ('not_started','pending','verified','rejected')) default 'not_started',rating numeric default 0,jobs_completed integer default 0,response_speed text default 'Usually responds fast',created_at timestamptz default now());
create table if not exists jobs (id uuid primary key default gen_random_uuid(),customer_id uuid references users(id) on delete cascade,provider_id uuid references users(id) on delete set null,provider_name text,provider_phone text,title text not null,description text,category text,location text not null,latitude numeric,longitude numeric,urgency text check (urgency in ('asap','today','scheduled')) default 'asap',status text check (status in ('requested','matched','quoted','assigned','payment_pending','paid','on_the_way','arrived','completed','cancelled')) default 'requested',scheduled_time timestamptz,created_at timestamptz default now());
create table if not exists quotes (id uuid primary key default gen_random_uuid(),job_id uuid references jobs(id) on delete cascade,provider_id uuid references users(id) on delete cascade,provider_name text,provider_phone text,estimate_min integer not null,estimate_max integer not null,eta_text text not null,message text,status text check (status in ('pending','accepted','declined','expired')) default 'pending',created_at timestamptz default now());
create table if not exists payments (id uuid primary key default gen_random_uuid(),job_id uuid references jobs(id) on delete cascade,quote_id uuid references quotes(id) on delete set null,amount_pence integer not null,platform_fee_pence integer default 0,stripe_checkout_session_id text,stripe_payment_intent_id text,status text check (status in ('unpaid','checkout_started','deposit_paid','paid','refunded')) default 'unpaid',created_at timestamptz default now());
create table if not exists messages (id uuid primary key default gen_random_uuid(),job_id uuid references jobs(id) on delete cascade,sender_id uuid references users(id) on delete cascade,message text not null,created_at timestamptz default now());
create table if not exists reviews (id uuid primary key default gen_random_uuid(),job_id uuid references jobs(id) on delete cascade,customer_id uuid references users(id) on delete cascade,provider_id uuid references users(id) on delete cascade,rating integer check (rating between 1 and 5),review_text text,created_at timestamptz default now());
create table if not exists notifications (id uuid primary key default gen_random_uuid(),user_id uuid references users(id) on delete cascade,job_id uuid references jobs(id) on delete cascade,title text not null,body text not null,read boolean default false,created_at timestamptz default now());
alter table users enable row level security;alter table provider_profiles enable row level security;alter table jobs enable row level security;alter table quotes enable row level security;alter table payments enable row level security;alter table messages enable row level security;alter table reviews enable row level security;alter table notifications enable row level security;
create policy "users can read own profile" on users for select using (auth.uid() = id);
create policy "users can insert own profile" on users for insert with check (auth.uid() = id);
create policy "users can update own profile" on users for update using (auth.uid() = id);
create policy "providers can manage own provider profile" on provider_profiles for all using (auth.uid() = user_id) with check (auth.uid() = user_id);
create policy "provider profiles are readable for marketplace search" on provider_profiles for select using (true);
create policy "customers can create own jobs" on jobs for insert with check (auth.uid() = customer_id);
create policy "related users can read open jobs" on jobs for select using (provider_id is null or auth.uid() = customer_id or auth.uid() = provider_id);
create policy "related users can update jobs" on jobs for update using (auth.uid() = customer_id or auth.uid() = provider_id or provider_id is null);
create policy "providers can create quotes" on quotes for insert with check (auth.uid() = provider_id);
create policy "related users can read quotes" on quotes for select using (auth.uid() = provider_id or exists (select 1 from jobs where jobs.id = quotes.job_id and jobs.customer_id = auth.uid()));
create policy "customers can accept quotes" on quotes for update using (exists (select 1 from jobs where jobs.id = quotes.job_id and jobs.customer_id = auth.uid()));
create policy "related users can read payments" on payments for select using (exists (select 1 from jobs where jobs.id = payments.job_id and (jobs.customer_id = auth.uid() or jobs.provider_id = auth.uid())));
create policy "customers can create payment records" on payments for insert with check (exists (select 1 from jobs where jobs.id = payments.job_id and jobs.customer_id = auth.uid()));
create policy "related users can read messages" on messages for select using (exists (select 1 from jobs where jobs.id = messages.job_id and (jobs.customer_id = auth.uid() or jobs.provider_id = auth.uid())));
create policy "related users can send messages" on messages for insert with check (exists (select 1 from jobs where jobs.id = messages.job_id and (jobs.customer_id = auth.uid() or jobs.provider_id = auth.uid())));
create policy "related users can manage reviews" on reviews for all using (auth.uid() = customer_id or auth.uid() = provider_id);
create policy "users can read own notifications" on notifications for select using (auth.uid() = user_id);
create policy "users can update own notifications" on notifications for update using (auth.uid() = user_id);
alter publication supabase_realtime add table jobs;
alter publication supabase_realtime add table quotes;
alter publication supabase_realtime add table payments;
alter publication supabase_realtime add table messages;
alter publication supabase_realtime add table notifications;
